// Build the Claude system prompt from tenant profile + conversation payload.
// Returns { system, user } for the Anthropic Messages API.
const profile = $input.first().json;
const webhook = $node['Webhook: SMS Convo Enrichment'].json;

const conversation = webhook.conversation_history || '';
const contactPhone = webhook.contact_phone || '';
const priorTouches = webhook.prior_touches || 0;

const businessName = profile.business_name || 'the business';
const vertical = profile.vertical || 'home services';
const voicePersona = profile.voice_persona || 'professional';
const brandTone = profile.brand_tone || 'warm';
const faqs = (profile.details?.top_faqs || []).slice(0, 8);
const objections = (profile.details?.common_objections || []).slice(0, 6);
const bookingRules = profile.details?.booking_rules || {};

const systemLines = [
  `You are the SMS conversation analyst for ${businessName}, a ${vertical} contractor.`,
  `Voice persona: ${voicePersona}. Brand tone: ${brandTone}.`,
  '',
  'Your job: read the SMS thread and output a single JSON object summarizing it for the decision engine.',
  '',
  'Output JSON keys (no prose outside the JSON):',
  '  intent:        string - book, reschedule, price_inquiry, complaint, info, other',
  '  bookingScore:  integer 0-10 - likelihood they book in the next 7 days',
  '  urgency:       low | medium | high',
  '  sentiment:     negative | neutral | positive',
  '  actionItems:   string[] - 1-5 short follow-ups for the operator',
  '  objectionFlag: null OR a label from KNOWN_OBJECTIONS if raised'
];

if (faqs.length) {
  systemLines.push('', 'Top FAQs for this business (context only, do not answer them here):');
  for (const f of faqs) systemLines.push(`  - ${f.question || f}`);
}
if (objections.length) {
  systemLines.push('', 'KNOWN_OBJECTIONS:');
  for (const o of objections) systemLines.push(`  - ${o.label || o}`);
}
if (bookingRules && Object.keys(bookingRules).length) {
  systemLines.push('', 'Booking rules:');
  for (const [k, v] of Object.entries(bookingRules)) systemLines.push(`  - ${k}: ${v}`);
}

const system = systemLines.join('\n');
const user = [
  'Analyze this SMS thread and return ONLY the JSON described above.',
  '',
  `Customer phone: ${contactPhone}`,
  `Prior touches with this customer: ${priorTouches}`,
  '',
  'Thread:',
  conversation
].join('\n');

return [{ json: { system, user, profile } }];
